import{_ as a,o as t,c as o,a2 as i}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"ADR-032 — Font and script strategy (Wave 1)","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-032.md","filePath":"adr/ADR-032.md"}'),n={name:"adr/ADR-032.md"};function r(s,e,d,c,l,h){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-032-—-font-and-script-strategy-wave-1" tabindex="-1">ADR-032 — Font and script strategy (Wave 1) <a class="header-anchor" href="#adr-032-—-font-and-script-strategy-wave-1" aria-label="Permalink to &quot;ADR-032 — Font and script strategy (Wave 1)&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-04 RFC anchor · <code>docs/rfc/RFC-010.md</code> (closed by ADR-031 + this ADR + ADR-033) Scope · Wave 1 baseline; CJK + RTL now resolved by follow-up ADRs</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>RFC-010 OQ-2 raised three distinct script-handling concerns: CJK fonts (Wave 2), RTL layout (Wave 3 — Arabic), and Devanagari fonts (Wave 3 — Hindi). ADR-031 grouped these into waves but didn&#39;t decide the technical approach. This ADR closes the Wave 1 question and explicitly defers Wave 2 + Wave 3 to follow-up ADRs scheduled with their respective waves.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p><strong>Wave 1 (Latin script — <code>es</code>, <code>fr</code>, <code>de</code>, <code>pt-BR</code>, <code>it</code>): no new font work.</strong></p><p>The existing font stack — <code>Bebas Neue</code> (titles), <code>Space Mono</code> (data / HUD), <code>Crimson Pro</code> (editorial) — already covers the Latin-extended characters required for all five Wave 1 languages, including Spanish accented vowels (á / é / í / ó / ú / ñ / ¿ / ¡), French accents and ligatures (à / â / ç / é / è / ê / ë / î / ï / ô / œ / ù / û / ü), German umlauts and eszett (ä / ö / ü / ß / ẞ), Portuguese-BR accents (ã / õ / ç + Spanish + French overlap), and Italian accents (à / è / é / ì / í / ò / ù).</p><p>Coverage was verified against the Google Fonts canonical glyph table for each font family.</p><p><strong>Wave 2 (CJK — <code>zh-CN</code>, <code>ja</code>, <code>ko</code>): resolved by ADR-044.</strong></p><p>See <code>docs/adr/ADR-044.md</code> for the accepted Wave 2 decision.</p><p><strong>Wave 3 (Devanagari — <code>hi</code>; Cyrillic — <code>ru</code>; Arabic RTL — <code>ar</code>): deferred.</strong></p><p>Three separate decisions; one follow-up ADR per concern when Wave 3 is scheduled:</p><ul><li>Devanagari font (likely Noto Sans Devanagari, ~400 KB)</li><li>Cyrillic glyph coverage audit of existing fonts; add Noto Sans Cyrillic if incomplete</li><li>Arabic RTL: resolved by <code>docs/adr/ADR-045.md</code>.</li></ul><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>Wave 1 ships zero font bytes and zero new infrastructure — translation is a content-only operation per ADR-017&#39;s locale-overlay architecture. Deferring Wave 2 / 3 decisions until they&#39;re actually scheduled avoids speculative work and keeps the surface area of this ADR honest: it documents the Wave 1 reality, not a fiction about all eleven languages.</p><p>The &quot;deferred to follow-up ADR&quot; language is intentional — it makes the decision-debt visible in the ADR registry and prevents Wave 2 / 3 from silently inheriting a default that wasn&#39;t actually chosen.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Decide CJK + RTL strategy now</strong>, before Wave 2 / 3 are scheduled — premature; the trade-offs (bundle-size budget, browser support for <code>font-display: swap</code>, prevalence of CSS logical properties in our tree) shift over time and benefit from being decided in context.</li><li><strong>Pre-load Noto Sans CJK in v0.3.x</strong> to save Wave 2 work — adds ~2 MB to every user&#39;s first paint regardless of locale; rejected on bundle-cost grounds.</li><li><strong>Single global font stack with all scripts</strong> (e.g. Noto Sans variable family) — covers everything but loses the typographic identity of <code>Bebas Neue</code> + <code>Crimson Pro</code>; rejected on design grounds.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p>Positive: Wave 1 ships immediately with no font work; Wave 2 / 3 decision points are explicit and registry-tracked; bundle-cost stays at current baseline until a Wave 2 / 3 language is actually scheduled.</p><p>Negative: this ADR will be superseded (or extended) twice as Wave 2 + Wave 3 follow-up ADRs land; the supersession chain needs to be kept current in CLAUDE.md.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li>No file changes required for Wave 1 font strategy.</li><li><code>scripts/fetch-assets.ts</code> already pulls the three Wave-1-sufficient font families.</li><li>Wave 2 CJK strategy is now tracked in <code>docs/adr/ADR-044.md</code>.</li><li>Wave 3 Arabic RTL strategy is now tracked in <code>docs/adr/ADR-045.md</code>.</li><li><code>sr-Cyrl</code> gate was later documented in <code>docs/adr/ADR-043.md</code>.</li></ul>',23)])])}const f=a(n,[["render",r]]);export{u as __pageData,f as default};
